#!/usr/bin/env bash
# unifi-controller-upgrade-migrati.sh — UniFi controller upgrade / migration SOP walkthrough for UBNT/UniFi 企业 Wi-Fi 工程.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="UBNT/UniFi 企业 Wi-Fi 工程"
WORKFLOW="UniFi controller upgrade / migration"

usage() {
  cat <<EOF
unifi-controller-upgrade-migrati.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./unifi-controller-upgrade-migrati.sh             # interactive
  ./unifi-controller-upgrade-migrati.sh --dry-run
  ./unifi-controller-upgrade-migrati.sh --json
  ./unifi-controller-upgrade-migrati.sh --explain
  ./unifi-controller-upgrade-migrati.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "UniFi controller upgrade / migration" 工作流。

一句话: A new Network App major version released OR a CVE was disclosed — must upgrade with rollback path documented (evidence: [T03-S011, T03-S006, T03-S023])

入门 SOP 共 7 步, 失败模式自检 8 项。

相关心智模型:
  • 容量优先, 覆盖次之 (Capacity-first, coverage second): 80 人密集办公的 Wi-Fi 瓶颈不是覆盖, 是同信道干扰 (CCI) — 加 AP 反而让网络更慢; 工程师先算 airtime budget, 后摆 AP.
  • Retry rate > RSSI (重试率比信号强度更能定位问题): 客户跟你说 "信号差", 你先要 retry % 和 channel utilization, 不要 RSSI — RSSI 满格但 retry 30% (业内估计 — CCI 阈值) 是 CCI /

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Read release notes + CVE diff**: check blog.ui.com release notes + community.ui.com advisories. What changed, what's the CVE impact, what's the rollback path UBNT supports. Skip → upgrade introduces breaking config change you weren't aware of."
  "**Snapshot backup**: download config backup from controller → encrypted offsite copy. Note current AP firmware versions (one per model). Skip → can't roll back; data loss if upgrade corrupts."
  "**Check version compatibility matrix**: AP firmware ≥ controller required version; some old AP models drop out of support (e.g., legacy UAP-AC-Lite no longer in current Network App). Skip → APs un-adopt themselves silently post-upgrade."
  "**Schedule maintenance window**: announce + confirm with users. Upgrade affects controller GUI; AP firmware reboot is per-AP and clients re-associate. Skip → user backlash + missed business impact."
  "**Upgrade controller first, then APs in batches**: controller upgrade should NOT auto-update APs without your trigger. Test connectivity with 1 AP after controller upgrade before mass-upgrading APs. Skip → mass AP outage if controller upgrade is buggy."
  "**Validate**: open Network app, check all APs adopted + healthy, walk WiFiman, run iperf3, confirm all SSIDs broadcasting, check controller log for errors. Skip → silent partial-failures (one SSID disappeared from one AP)."
  "**Document + close**: write upgrade ticket including before/after versions, who/when, any issues, rollback NOT needed (or done). Skip → no audit trail, can't diagnose drift later."
)
declare -a FAILURE_MODES=(
  "**F1**: Auto-update enabled on production Cloud Key — controller silently upgrades to a release with a regression that breaks RADIUS auth at 2am, no one knew it happened."
  "**F2**: Skip the CVE diff check — apply only feature releases monthly, miss a critical security advisory issued between releases."
  "**F3**: Upgrade controller + all APs simultaneously, hit a controller bug, can't downgrade APs to match — mass disruption (evidence: [T03-S023] community reports)."
  "**Sources**:"
  "[Primary] UBNT blog release notes (T03-S011)"
  "[Primary] Lawrence Systems CVE coverage (T03-S006)"
  "[Primary] UBNT help / community (T03-S009, T03-S024)"
  "[Reference] r/Ubiquiti upgrade discussions (T03-S023)"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "unifi-controller-upgrade-migrati-walkthrough"
fi
